1	const fs = require('fs');
2	const path = require('path');
3	
4	const read = (f) => fs.readFileSync(path.join(__dirname, '..', f), 'utf-8');
5	
6	describe('Documentation Accuracy', () => {
7	  const readme = read('README.md');
8	  const apiSpec = read('docs/api-spec.md');
9	  const openapi = read('api/src/docs/openapi.json');
10	  const setupSh = read('setup.sh');
11	  const seedJs = read('api/src/db/seed.js');
12	
13	  describe('Bootstrap credential retrieval', () => {
14	    test('README documents file-based retrieval', () => {
15	      expect(readme).toContain('.bootstrap-credentials');
16	      expect(readme).not.toContain('grep -A 10 BOOTSTRAP');
17	    });
18	
19	    test('setup.sh documents file-based retrieval', () => {
20	      expect(setupSh).toContain('.bootstrap-credentials');
21	      expect(setupSh).not.toContain('grep -A 10 BOOTSTRAP');
22	    });
23	
24	    test('seed.js writes to file, not logs', () => {
25	      expect(seedJs).toContain('.bootstrap-credentials');
26	      expect(seedJs).toContain('writeFileSync');
27	    });
28	  });
29	
30	  describe('OpenAPI endpoint docs', () => {
31	    test('README points to /api/docs for Swagger UI', () => {
32	      expect(readme).toContain('Swagger UI');
33	      expect(readme).toContain('/api/docs');
34	    });
35	
36	    test('README points to /api/docs.json for raw JSON', () => {
37	      expect(readme).toContain('/api/docs.json');
38	    });
39	
40	    test('api-spec.md points to /api/docs.json for JSON', () => {
41	      expect(apiSpec).toContain('/api/docs.json');
42	    });
43	  });
44	
45	  describe('Sensor ingest auth documentation', () => {
46	    test('api-spec.md documents device auth headers', () => {
47	      expect(apiSpec).toContain('X-Device-Id');
48	      expect(apiSpec).toContain('X-Device-Secret');
49	      expect(apiSpec).not.toMatch(/ingest.*no auth/i);
50	    });
51	
